import pg from "pg";
import { SequelizeOptions } from "sequelize-typescript";

export const commonSequelizeConfig = (
  min?: number,
  max?: number,
): SequelizeOptions => {
  const options: SequelizeOptions = {
    logging: false,
    dialectModule: pg,
    retry: {
      // Error types: https://sequelize.org/api/v6/identifiers.html#errors
      match: [
        /ConnectionError/, // Fix pg vercel bug: https://github.com/orgs/vercel/discussions/234
      ],
      max: 3,
    },
  };

  if (min !== undefined || max !== undefined) {
    options.pool = {};
    if (min !== undefined) options.pool.min = min;
    if (max !== undefined) options.pool.max = max;
  }

  return options;
};

import { procedure, router } from "../trpc";
import { z } from "zod";
import { addRole, displayName } from "../../shared/Role";
import db from "../database/db";
import sequelize from "../database/sequelize";
import { authUser } from "../auth";
import { generalBadRequestError } from "../errors";
import { MenteeStatus } from "../../shared/MenteeStatus";
import { invalidateUserCache } from "../../pages/api/auth/[...nextauth]";
import { toPinyin } from "../../shared/strings";
import invariant from "../../shared/invariant";
import { menteeSourceField } from "../../shared/applicationFields";
import { Transaction } from "sequelize";
import User from "../../shared/User";
import { notifyRolesIgnoreError } from "api/notify";

const validate = procedure
  .use(authUser())
  .input(
    z.object({
      name: z.string(),
      pearlId: z.string(),
      nationalIdLastFour: z.string(),
      wechat: z.string(),
    }),
  )
  .mutation(async ({ ctx: { me }, input }) => {
    await sequelize.transaction(async (transaction) => {
      await validateImpl(
        me,
        input.name,
        input.pearlId,
        input.nationalIdLastFour,
        input.wechat,
        transaction,
      );
    });
  });

export async function validateImpl(
  me: User,
  name: string,
  pearlId: string,
  nationalIdLastFour: string,
  wechat: string,
  transaction: Transaction,
) {
  const student = await db.PearlStudent.findOne({
    where: {
      pearlId,
      name,
      lowerCaseNationalIdLastFour: nationalIdLastFour.toLowerCase(),
    },
    attributes: ["pearlId", "userId"],
    lock: true,
    transaction,
  });

  if (!student) {
    notifyRolesIgnoreError(
      ["UserAdmin"],
      "珍珠生验证失败",
      `用户 ${me.id} 认证珍珠生失败：` +
        `"${name}"、"${pearlId}"、"${nationalIdLastFour}"`,
    );

    throw generalBadRequestError("珍珠生信息不匹配。");
  }

  if (student.userId) {
    notifyRolesIgnoreError(
      ["UserAdmin"],
      "珍珠生重复验证",
      `用户 ${me.id} （${name}）试图用已被验证的` +
        `珍珠生号 ${pearlId} 进行验证。请联系学生管理员。`,
    );

    throw generalBadRequestError(
      `此珍珠生号已被验证。` + `请联系${displayName("UserAdmin")}。`,
    );
  }

  // Update mentee status only if it is null.
  const menteeStatus: MenteeStatus =
    me.menteeStatus === null ? "现届学子" : me.menteeStatus;

  await student.update({ userId: me.id }, { transaction });

  const user = await db.User.findByPk(me.id, {
    attributes: ["id", "menteeApplication"],
    transaction,
  });
  invariant(user, `User not found: ${me.id}`);

  const menteeApplication = {
    ...user.menteeApplication,
    [menteeSourceField]: "珍珠生：" + pearlId,
  };

  // TODO: Consolidate with `createUser` in users.ts.
  await user.update(
    {
      name,
      pinyin: toPinyin(name),
      wechat,
      roles: addRole(me.roles, "Mentee"),
      menteeStatus,
      menteeApplication,
    },
    { transaction },
  );

  invalidateUserCache(me.id);
}

export async function uploadImpl(csvData: string) {
  // Parse CSV data
  const lines = csvData.trim().split("\n");

  // Parse and validate data
  const students: Array<{
    name: string;
    pearlId: string;
    lowerCaseNationalIdLastFour: string | null;
  }> = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim();
    if (!line) continue;

    const values = line.split(",").map((v) => v.trim());
    if (values.length < 2) {
      throw generalBadRequestError(`第${i + 1}行数据不完整`);
    }

    const name = values[0];
    const pearlId = values[1];
    const nationalIdLastFour = values[2] || null;

    if (!name || !pearlId) {
      throw generalBadRequestError(`第${i + 1}行：姓名和珍珠生编号不能为空`);
    }

    if (nationalIdLastFour && nationalIdLastFour.length !== 4) {
      throw generalBadRequestError(
        `第${i + 1}行：身份证号最后四位必须是4位数字`,
      );
    }

    students.push({
      name,
      pearlId,
      lowerCaseNationalIdLastFour: nationalIdLastFour?.toLowerCase() || null,
    });
  }

  // Use transaction to ensure atomicity
  const result = await sequelize.transaction(async (transaction) => {
    let updatedCount = 0;
    let insertedCount = 0;

    for (const student of students) {
      const existing = await db.PearlStudent.findByPk(student.pearlId, {
        attributes: ["pearlId"],
        transaction,
      });

      if (existing) {
        // Update existing record
        await existing.update(student, { transaction });
        updatedCount++;
      } else {
        // Insert new record
        await db.PearlStudent.create(student, { transaction });
        insertedCount++;
      }
    }

    return {
      total: students.length,
      updated: updatedCount,
      inserted: insertedCount,
    };
  });

  return result;
}

const upload = procedure
  .use(authUser())
  .input(
    z.object({
      csvData: z.string(),
    }),
  )
  .mutation(async ({ input }) => {
    return await uploadImpl(input.csvData);
  });

export default router({
  validate,
  upload,
});

import { initTRPC } from "@trpc/server";
import { Context } from "pages/api/v1/[trpc]";

const trpc = initTRPC.context<Context>().create();

// Base router and procedure helpers
export const router = trpc.router;
export const procedure = trpc.procedure;
export const middleware = trpc.middleware;

import { ip } from "./ip";
import { middleware } from "./trpc";
import { TRPCError } from "@trpc/server";
import Role, { isPermitted } from "../shared/Role";
import { getServerSession } from "next-auth/next";
import { authOptions } from "../pages/api/auth/[...nextauth]";
import crypto from "crypto";
import { internalServerError } from "./errors";

/**
 * Authenticate for APIs used by applications as opposed to end users. Usage:
 *
 * $ curl -H "Authorization: Bearer ${INTEGRATION_AUTH_TOKEN}" \
 *  "${BASE_URL}/api/v1/foo.bar"
 */
export const authIntegration = () =>
  middleware(async ({ ctx, next }) => {
    const token: string | undefined =
      ctx.req.headers["authorization"]?.split(" ")[1];

    if (!token) throw unauthorizedError();

    const expected = process.env.INTEGRATION_AUTH_TOKEN;
    if (!expected) {
      throw internalServerError("INTEGRATION_AUTH_TOKEN is not set.");
    }

    if (
      token.length !== expected.length ||
      // Use timingSafeEqual to prevent timing attacks.
      !crypto.timingSafeEqual(Buffer.from(token), Buffer.from(expected))
    ) {
      throw invalidTokenError();
    }

    return await next({ ctx: {} });
  });

/**
 * Authenticate for APIs used by end users as opposed to integration
 * applications.
 */
export const authUser = (permitted?: Role | Role[]) =>
  middleware(async ({ ctx, next }) => {
    const session = await getServerSession(
      ctx.req,
      ctx.res,
      authOptions(ctx.req),
    );
    if (!session) throw unauthorizedError();

    if (!isPermitted(session.me.roles, permitted)) throw forbiddenError();

    return await next({
      ctx: {
        me: session.me,
        session,
      },
    });
  });

/**
 * Authenticate for webhooks.
 */
export const authWebhook = middleware(async ({ next }) => {
  if (!process.env.WEBHOOK_TOKEN) {
    throw internalServerError("WEBHOOK_TOKEN is required but not set.");
  }
  return await next();
});

