/**
 * See docs/WeChat.md for details.
 */
import type { OAuthConfig, OAuthUserConfig } from "next-auth/providers";
import { unionId2Email } from "./fakeEmail";

/**
 * See docs/WeChat.md for unionid vs openid
 */
interface WeChatProfile {
  openid: string;
  nickname: string;
  sex: number;
  province: string;
  city: string;
  country: string;
  headimgurl: string;
  privilege: string[];
  unionid: string;
  [claim: string]: unknown;
}

export default function WeChatProvider(
  options: OAuthUserConfig<WeChatProfile> & {
    platformType: "OfficialAccount" | "WebsiteApp";
  },
): OAuthConfig<WeChatProfile> {
  const { clientId, clientSecret, platformType } = options;

  return {
    id: "wechat",
    name: "WeChat",
    type: "oauth",
    // style: { logo: "/img/wechat.svg", bg: "#fff", text: "#000" },
    checks: ["state"],

    // We need this option to allow next-auth to link 微信开放平台 & 微信公众平台
    // accounts that share the same UnionID. See docs/WeChat.md.
    allowDangerousEmailAccountLinking: true,

    authorization: {
      url:
        platformType === "OfficialAccount"
          ? "https://open.weixin.qq.com/connect/oauth2/authorize"
          : "https://open.weixin.qq.com/connect/qrconnect",
      params: {
        appid: clientId,
        scope:
          platformType === "OfficialAccount"
            ? "snsapi_userinfo"
            : "snsapi_login",
      },
    },

    token: {
      async request({ params }) {
        try {
          if (!params.code) throw new Error("No code provided");
          const url = new URL(
            "https://api.weixin.qq.com/sns/oauth2/access_token",
          );
          url.searchParams.set("appid", clientId);
          url.searchParams.set("secret", clientSecret);
          url.searchParams.set("code", params.code);
          url.searchParams.set("grant_type", "authorization_code");
          const response = await fetch(url);
          const data = await response.json();
          return { tokens: data };
        } catch (error) {
          console.error("WeChat token request failed:", error);
          throw new Error("微信登录失败,请重试");
        }
      },
    },

    userinfo: {
      async request({ tokens }) {
        if (!tokens.access_token) {
          throw new Error("未获取到微信授权");
        }
        const url = new URL("https://api.weixin.qq.com/sns/userinfo");
        url.searchParams.set("access_token", tokens.access_token!);
        url.searchParams.set("openid", String(tokens.openid));
        url.searchParams.set("lang", "zh_CN");
        const response = await fetch(url);
        return response.json();
      },
    },

    profile(profile) {
      return {
        // next-auth saves it to the `provider_account_id` column of the
        // `accounts` table.
        id: profile.unionid,

        // next-auth rely on email to search for existing users. We don't store
        // the email in the database. See code in adapter.ts.
        email: unionId2Email(profile.unionid),
      };
    },

    options,
  };
}

import type { OAuthConfig, OAuthUserConfig } from "next-auth/providers";
import { TokenSet } from "openid-client";
import { ssoUserId2Email } from "./fakeEmail";

export default function YuantuSsoProvider(
  options: OAuthUserConfig<any> & { issuer: string },
): OAuthConfig<any> {
  const { clientId, clientSecret, issuer } = options;

  return {
    id: "yuantu-sso",
    name: "YuanTu SSO",
    type: "oauth",
    // Our in-house OAuth2 provider signs id_token with HS256 (shared client
    // secret),
    // so we must override openid-client's RS256 default expectation.
    client: { id_token_signed_response_alg: "HS256" },
    clientId,
    clientSecret,
    issuer,
    // We need this option to allow next-auth to link  accounts that share the
    // same user id on the sso server.
    allowDangerousEmailAccountLinking: true,
    authorization: {
      url: `${issuer}/api/oauth2/authorize`,
      params: { scope: "openid profile email phone" },
    },
    token: { url: `${issuer}/api/oauth2/token` },
    userinfo: {
      url: `${issuer}/api/oauth2/userinfo`,
      // NextAuth otherwise uses only id_token claims for the profile when
      // `idToken` is enabled. Our id_token carries `sub` only; additional
      // fields such as name and phone number come from the OIDC userinfo
      // response (see `oauth2/userinfo.ts`).
      request({ client, tokens }) {
        return client.userinfo(
          tokens instanceof TokenSet ? tokens : new TokenSet(tokens),
        );
      },
    },
    checks: ["pkce", "state"],
    profile(profile) {
      // For more information on why we encode the ssoUserId into the email,
      // see WeChatProvider.profile() function.
      return {
        id: profile.sub,
        email: ssoUserId2Email(profile.sub),
        realEmail: profile.email ?? undefined,
        name: profile.name ?? undefined,
        phone: profile.phone_number ?? undefined,
      };
    },
    options,
  };
}

import { Op, Transaction } from "sequelize";
import { NotificationType } from "shared/UserPreference";
import db from "./database/db";
import { sms } from "./sms";
import { email } from "./email";
import getBaseUrl from "shared/getBaseUrl";
import Role from "shared/Role";
import sequelize from "./database/sequelize";

type Templates = {
  // AokSend email template id.
  email: string;
  // Submail SMS template ids.
  domesticSms: string;
  internationalSms: string;
};

export function notifyRolesIgnoreError(
  roles: Role[],
  subject: string,
  content: string,
) {
  const logError = (e: any) => {
    console.log(
      `notifyRolesIgnoreError() ignored error: ${roles}, ${subject}, ${e}`,
    );
  };
  try {
    // Do not use the transaction from the caller so the caller can proceed
    // without waiting for us.
    void sequelize.transaction(async (transaction) => {
      try {
        await notifyRoles(roles, subject, content, transaction);
      } catch (e) {
        logError(e);
      }
    });
  } catch (e) {
    logError(e);
  }
}

export async function notifyRoles(
  roles: Role[],
  subject: string,
  content: string,
  transaction: Transaction,
) {
  const userIds: Set<string> = new Set();
  for (const role of roles) {
    const users = await db.User.findAll({
      where: { roles: { [Op.contains]: [role] } },
      attributes: ["id"],
      transaction,
    });
    users.forEach((u) => userIds.add(u.id));
  }
  await notify(
    "基础",
    Array.from(userIds),
    {
      email: "E_114706970517",
      domesticSms: "JCGmM2",
      internationalSms: "2VFsY",
    },
    {
      subject,
      content,
    },
    transaction,
  );
}

/**
 * `templateVariables` should include variables needed for all three templates.
 */
export async function notify(
  type: NotificationType,
  userIds: string[],
  templates: Templates,
  templateVariables: Record<string, string>,
  transaction: Transaction,
) {
  const users = await db.User.findAll({
    where: { id: { [Op.in]: userIds } },
    attributes: ["email", "phone", "preference"],
    transaction,
  });

  const smsUsers = users.filter(
    (u) =>
      u.phone &&
      !u.preference?.smsDisabled?.includes("基础") &&
      !u.preference?.smsDisabled?.includes(type),
  );
  const smsPromise = sms(
    templates.domesticSms,
    templates.internationalSms,
    smsUsers.map((u) => ({
      to: u.phone!,
      vars: templateVariables,
    })),
  );

  const emailUsers = users.filter(
    (u) =>
      u.email &&
      !u.preference?.emailDisabled?.includes("基础") &&
      !u.preference?.emailDisabled?.includes(type),
  );
  const emailPromise = email(
    emailUsers.map((u) => u.email!),
    templates.email,
    templateVariables,
    getBaseUrl(),
  );

  // Parallelize to speed up the function
  await Promise.all([smsPromise, emailPromise]);
}

/**
 * Low-level API for sending transactional SMS. Use higher level API notify*()
 * when possible.
 */
import z from "zod";
import axios, { AxiosResponse } from "axios";
import { internalServerError } from "./errors";
import { chinaPhonePrefix } from "../shared/strings";

export const idTokenInternationalSmsTemplateId = "0Rr8G";

export async function sms(
  domesticTemplateId: string,
  internationalTemplateId: string,
  templateData: {
    to: string;
    vars: Record<string, string>;
  }[],
) {
  // Skip everything in unittest. https://stackoverflow.com/a/29183140
  if (typeof global.it === "function") return;

  console.log(
    `Sending SMS via Submail, template id:`,
    `["${domesticTemplateId}", "${internationalTemplateId}"],`,
    `data: ${JSON.stringify(templateData, null, 2)}`,
  );

  const domestic = templateData
    .filter((t) => t.to.startsWith(chinaPhonePrefix))
    .map((t) => ({
      to: t.to.slice(chinaPhonePrefix.length),
      vars: t.vars,
    }));
  if (domestic.length > 0) {
    const appid = process.env.SUBMAIL_DOMESTIC_APP_ID;
    const appKey = process.env.SUBMAIL_DOMESTIC_APP_KEY;
    if (!appKey || !appid) {
      console.log("Domestic Submail not configured. Skip actual API.");
      return;
    }

    const form = new FormData();
    form.append("appid", appid);
    form.append("signature", appKey);
    form.append("project", domesticTemplateId);
    form.append("multi", JSON.stringify(domestic));

    // https://www.mysubmail.com/documents/eM4rY2
    handleResponse(
      await axios.post("https://api-v4.mysubmail.com/sms/multixsend", form, {
        headers: { "Content-Type": "multipart/form-data" },
      }),
    );
  }

  const international = templateData.filter(
    (t) => !t.to.startsWith(chinaPhonePrefix),
  );
  if (international.length > 0) {
    const appid = process.env.SUBMAIL_INTERNATIONAL_APP_ID;
    const appKey = process.env.SUBMAIL_INTERNATIONAL_APP_KEY;
    if (!appKey || !appid) {
      console.log("International Submail not configured. Skip actual API.");
      return;
    }

    const form = new FormData();
    form.append("appid", appid);
    form.append("signature", appKey);
    form.append("project", internationalTemplateId);
    form.append("multi", JSON.stringify(international));

    // https://www.mysubmail.com/documents/B70hy
    const response = await axios.post(
      "https://api-v4.mysubmail.com/internationalsms/multixsend",
      form,
      { headers: { "Content-Type": "multipart/form-data" } },
    );

    /**
     * Ignore errors for international SMS that is not for phone verification.
     * This is because Submail.com doesn't guarantee the delivery of these SMS.
     * For each country, Submail.com may need the service provider to obtain
     * permits from that country's mobile operators first to send
     * non-verification SMS to that country.
     */
    handleResponse(
      response,
      internationalTemplateId !== idTokenInternationalSmsTemplateId,
    );
  }
}

function handleResponse(response: AxiosResponse, ignoreError: boolean = false) {
  if (response.status !== 200) {
    console.log(
      `部分短信发送失败（忽略错误=${ignoreError}）：`,
      response.status,
      response.data,
    );
    if (!ignoreError) throw internalServerError("短信发送失败。请联系客服。");
  }

  const zResult = z.object({
    status: z.string(),
    code: z.number().optional(),
    msg: z.string().optional(),
  });

  // Handle either a single result or an array of multiple results
  const result = z.union([zResult, z.array(zResult)]).parse(response.data);
  const results = Array.isArray(result) ? result : [result];

  if (results.some((r) => r.status !== "success")) {
    console.log(`部分短信发送失败（忽略错误=${ignoreError}）：`, results);
    if (!ignoreError) throw internalServerError("短信发送失败。请联系客服。");
  }
}

